import React, { useEffect, useState } from "react";

const AccountSettings = () => {
    const [user, setUser] = useState(null);
    const [error, setError] = useState("");
    const [email, setEmail] = useState(localStorage.getItem("email") || "");

    useEffect(() => {
        console.log("🔍 Email actuel dans AccountSettings:", email);
        if (!email) {
            setError("🚨 Aucun email trouvé. Veuillez vous reconnecter.");
            return;
        }

        const fetchUserByEmail = async () => {
            try {
                const response = await fetch(`http://localhost:5001/user/email?email=${email}`);
                if (!response.ok) throw new Error("Utilisateur non trouvé.");
                const data = await response.json();
                setUser(data);
            } catch (err) {
                setError("Erreur lors de la récupération des informations.");
                console.error(err);
            }
        };

        fetchUserByEmail();
    }, [email]); // Ajout de `email` pour surveiller les changements

    return (
        <div style={{ padding: "20px" }}>
            <h2>Paramètres du compte</h2>
            {error && <p style={{ color: "red" }}>{error}</p>}
            {user ? (
                <div>
                    <p><strong>Nom :</strong> {user.name}</p>
                    <p><strong>Email :</strong> {user.email}</p>
                </div>
            ) : (
                !error && <p>Chargement des informations...</p>
            )}
        </div>
    );
};

export default AccountSettings;
